'use strict';

// Duration parser. See docs/timeouts.md for the contract and
// docs/conventions.md for the format rules (compound segments sum, ms is
// tokenized before m, a bare integer is milliseconds, the whole string must
// be consumed).
//
// Returns a non-negative integer number of milliseconds; throws on an
// unparseable input. Pure: no mutation, no I/O.
function parseDuration(str) {
  if (typeof str !== 'string' || str.length === 0) {
    throw new Error(`parseDuration: unparseable input: ${JSON.stringify(str)}`);
  }

  // Bare integer: no unit means milliseconds
  if (/^\d+$/.test(str)) {
    return parseInt(str, 10);
  }

  const UNITS = { ms: 1, s: 1000, m: 60000, h: 3600000, d: 86400000 };
  // ms must come before m so the two-letter unit takes precedence
  const UNIT_PATTERN = /(\d+)(ms|s|m|h|d)/y;

  let total = 0;
  let lastIndex = 0;

  UNIT_PATTERN.lastIndex = 0;
  while (lastIndex < str.length) {
    UNIT_PATTERN.lastIndex = lastIndex;
    const match = UNIT_PATTERN.exec(str);
    if (!match || match.index !== lastIndex) {
      throw new Error(`parseDuration: unparseable input: ${JSON.stringify(str)}`);
    }
    total += parseInt(match[1], 10) * UNITS[match[2]];
    lastIndex = UNIT_PATTERN.lastIndex;
  }

  return total;
}

module.exports = { parseDuration };

